import{c as t,Q as l,j as a,m as i}from"./chunks/framework.BXc4yaFE.js";const h=JSON.parse('{"title":"36. GitHub: Claude Code Best Practice","description":"","frontmatter":{"url":"https://github.com/shanraisshan/claude-code-best-practice","status":"SUCCESS","date_fetched":"2026-05-18T00:00:00.000Z","repository":"shanraisshan/claude-code-best-practice"},"headers":[],"relativePath":"research/ai-articles/36-github-shanraisshan-claude-best-practice.md","filePath":"research/ai-articles/36-github-shanraisshan-claude-best-practice.md","lastUpdated":1779894392000}'),o={name:"research/ai-articles/36-github-shanraisshan-claude-best-practice.md"};function r(s,e,n,d,c,g){return l(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="_36-github-claude-code-best-practice" tabindex="-1">36. GitHub: Claude Code Best Practice <a class="header-anchor" href="#_36-github-claude-code-best-practice" aria-label="Permalink to &quot;36. GitHub: Claude Code Best Practice&quot;">​</a></h1><h2 id="核心摘要-繁體中文" tabindex="-1">核心摘要（繁體中文） <a class="header-anchor" href="#核心摘要-繁體中文" aria-label="Permalink to &quot;核心摘要（繁體中文）&quot;">​</a></h2><p>該儲存庫是一份關於 Claude Code 開發工作流程的完整指南，涵蓋從基礎概念到進階代理工程模式。强調實踐工作流程而非單純配置，記錄全球團隊使用的 12 種主要開發方法。</p><h3 id="八項核心功能" tabindex="-1">八項核心功能 <a class="header-anchor" href="#八項核心功能" aria-label="Permalink to &quot;八項核心功能&quot;">​</a></h3><ol><li><strong>Subagents（子代理）</strong>：具有專門上下文的自主代理，避免主會話過度膨脹</li><li><strong>Commands（命令）</strong>：透過 <code>.claude/commands/</code> 定義重複性工作流程的快捷指令</li><li><strong>Skills（技能）</strong>：在 <code>.claude/skills/</code> 中組織漸進式功能披露</li><li><strong>Workflows（工作流程）</strong>：連接命令、代理和技能的編排模式</li><li><strong>Hooks（鉤子）</strong>：事件驅動自動化（PreToolUse、PostToolUse、Stop）</li><li><strong>MCP Servers</strong>：模型上下文協議集成</li><li><strong>Settings（設定）</strong>：透過 <code>.claude/settings.json</code> 的配置</li><li><strong>Memory（記憶）</strong>：透過 CLAUDE.md 和 <code>.claude/rules/</code> 的上下文管理</li></ol><h3 id="_12-大開發工作流程" tabindex="-1">12 大開發工作流程 <a class="header-anchor" href="#_12-大開發工作流程" aria-label="Permalink to &quot;12 大開發工作流程&quot;">​</a></h3><p>儲存庫記錄了全球團隊使用的主要方法學，包括：</p><ul><li><strong>Superpowers</strong>（188k stars）：Git worktree 驅動開發與子代理實現</li><li><strong>Everything Claude Code</strong>：Plan → TDD → Code Review → Security → E2E 流程</li><li><strong>Spec Kit</strong>：基於憲法的規格方法</li><li><strong>gstack</strong>：CEO/工程/設計審查門檻與 HTML 設計生成</li><li><strong>BMAD-METHOD</strong>：Epic 驅動故事管理與回顧</li></ul><p><strong>共同模式</strong>：Research → Plan → Execute → Review → Ship</p><h3 id="進階功能-beta-與實驗中" tabindex="-1">進階功能（Beta 與實驗中） <a class="header-anchor" href="#進階功能-beta-與實驗中" aria-label="Permalink to &quot;進階功能（Beta 與實驗中）&quot;">​</a></h3><ul><li><strong>Ultrareview</strong>（Beta）：代碼審查與任務追蹤</li><li><strong>Auto Mode</strong>（Beta）：基於模型的安全權限分類</li><li><strong>Computer Use</strong>（Beta）：透過 MCP 的桌面自動化</li><li><strong>Agent Teams</strong>（Beta）：透過 tmux 的並行開發</li><li><strong>Agent SDK</strong>：用於外部代理系統的 Node/Python 套件</li><li><strong>Scheduled Tasks</strong>：透過 <code>/loop</code> 和 <code>/schedule</code> 的循環自動化</li></ul><h3 id="_83-項實踐技巧" tabindex="-1">83 項實踐技巧 <a class="header-anchor" href="#_83-項實踐技巧" aria-label="Permalink to &quot;83 項實踐技巧&quot;">​</a></h3><p>組織於九個類別：</p><p><strong>Prompting（提示）</strong></p><ul><li>用對比挑戰 Claude，不要微管理實現</li><li>邊界條件比完整規格更重要</li></ul><p><strong>Planning（計劃）</strong></p><ul><li>始終以分階段受控計劃開始</li><li>每階段包含單元、自動化和整合測試</li><li>垂直切片優於水平分階段</li></ul><p><strong>Context Management（上下文管理）</strong></p><ul><li>300-400k 代幣時出現上下文衰退</li><li>40% 使用率時性能開始下降；60% 時應考慮結束任務</li><li><code>/compact</code> 搭配提示優於自動壓縮</li></ul><p><strong>Session Management（會話管理）</strong></p><ul><li>新任務應建立新會話；相關任務可重用</li><li>使用 <code>/rename</code> 標記重要會話，以便 <code>/resume</code></li><li>每個轉折都是選擇點：繼續、回溯、清除、壓縮或子代理</li></ul><p><strong>Agent &amp; Skill Design（代理與技能設計）</strong></p><ul><li>選擇特定功能的子代理而非通用角色</li><li>使用 <code>context: fork</code> 在隔離子代理中運行技能</li><li>技能描述應作為觸發條件而非摘要</li></ul><p><strong>開發工作流程</strong></p><ul><li>使用 <code>/rewind</code> 而非累積修正——回到失敗前的狀態</li><li>測試時計算：一個代理產生代碼，另一個在隔離環境中查找錯誤</li><li>跨模型配置：Opus（計劃）+ Sonnet（編碼）+ 思考模式</li></ul><h3 id="企業應用案例" tabindex="-1">企業應用案例 <a class="header-anchor" href="#企業應用案例" aria-label="Permalink to &quot;企業應用案例&quot;">​</a></h3><p>儲存庫記錄 Claude Code 功能如何替代現有服務：</p><ul><li><strong>Code Review</strong> 替代 Greptile、CodeRabbit</li><li><strong>Voice Dictation</strong> 替代 Wispr Flow</li><li><strong>Computer Use</strong> 替代 OpenAI 的計算機使用代理</li><li><strong>Agent SDK</strong> 替代 LangChain、CrewAI</li></ul><h3 id="跨模型整合" tabindex="-1">跨模型整合 <a class="header-anchor" href="#跨模型整合" aria-label="Permalink to &quot;跨模型整合&quot;">​</a></h3><p>支援三種機制整合其他模型（Codex、Gemini、DeepSeek 等）：</p><ul><li><strong>Plugins</strong>：另一模型的 CLI 在 Claude Code 內執行</li><li><strong>MCP</strong>：透過模型上下文協議</li><li><strong>Router</strong>：交換 API 端點至不同提供商</li></ul><hr><h2 id="關鍵數據-引用" tabindex="-1">關鍵數據/引用 <a class="header-anchor" href="#關鍵數據-引用" aria-label="Permalink to &quot;關鍵數據/引用&quot;">​</a></h2><h3 id="核心統計" tabindex="-1">核心統計 <a class="header-anchor" href="#核心統計" aria-label="Permalink to &quot;核心統計&quot;">​</a></h3><ul><li><strong>83 項具體提示</strong>：涵蓋提示、規劃、上下文、會話、代理、命令、技能和除錯</li><li><strong>12 種主要工作流程</strong>：來自全球團隊的實踐方法學</li><li><strong>8 項核心功能</strong>：Claude Code 的主要能力支柱</li></ul><h3 id="實踐建議-每日工作流程" tabindex="-1">實踐建議（每日工作流程） <a class="header-anchor" href="#實踐建議-每日工作流程" aria-label="Permalink to &quot;實踐建議（每日工作流程）&quot;">​</a></h3><ol><li>根據任務複雜度選擇新會話或現有會話</li><li>主動管理上下文——監控使用率，在 40-60% 時規劃變化</li><li>使用重新繪製而非修正累積錯誤</li><li>為重複性工作構建命令與技能，避免重新提示</li></ol><h3 id="上下文衰退閾值" tabindex="-1">上下文衰退閾值 <a class="header-anchor" href="#上下文衰退閾值" aria-label="Permalink to &quot;上下文衰退閾值&quot;">​</a></h3><ul><li><strong>40%</strong> 使用率：性能開始下降</li><li><strong>60%</strong> 使用率：應考慮結束任務</li><li><strong>300-400k</strong> 代幣：明顯衰退開始</li></ul><hr><h2 id="技術棧與工具" tabindex="-1">技術棧與工具 <a class="header-anchor" href="#技術棧與工具" aria-label="Permalink to &quot;技術棧與工具&quot;">​</a></h2><ul><li><strong>版本控制</strong>：Git worktree</li><li><strong>自動化</strong>：MCP、Hooks</li><li><strong>協調</strong>：Agent Teams、Workflows</li><li><strong>測試</strong>：TDD、SDD、BDD</li></ul><hr>',43)])])}const p=t(o,[["render",r]]);export{h as __pageData,p as default};
